import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
} from '@angular/core';
import { MatExpansionModule } from '@angular/material/expansion';

export interface MfAccordionPanel {
  title: string;
  description?: string;
  content: string;
  expanded?: boolean;
  disabled?: boolean;
}

/**
 * Accordion de la librería ng-comps.
 * Envuelve Angular Material `mat-accordion` / `mat-expansion-panel` y expone
 * una API uniforme con look and feel de marca.
 */
@Component({
  selector: 'mf-accordion',
  imports: [MatExpansionModule],
  template: `
    <mat-accordion [multi]="multi()" [class]="hostClasses()">
      @for (panel of panels(); track panel.title) {
        <mat-expansion-panel
          [expanded]="panel.expanded ?? false"
          [disabled]="panel.disabled ?? false"
        >
          <mat-expansion-panel-header>
            <mat-panel-title>{{ panel.title }}</mat-panel-title>
            @if (panel.description) {
              <mat-panel-description>{{ panel.description }}</mat-panel-description>
            }
          </mat-expansion-panel-header>
          <p>{{ panel.content }}</p>
        </mat-expansion-panel>
      }
    </mat-accordion>
  `,
  styleUrl: './mf-accordion.component.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class MfAccordionComponent {
  /** Paneles del accordion */
  readonly panels = input.required<MfAccordionPanel[]>();
  /** Permite múltiples paneles abiertos */
  readonly multi = input(false);

  readonly hostClasses = computed(() => 'mf-accordion');
}

import {
  ChangeDetectionStrategy,
  ChangeDetectorRef,
  Component,
  computed,
  effect,
  forwardRef,
  inject,
  input,
  output,
  signal,
} from '@angular/core';
import {
  ControlValueAccessor,
  NG_VALUE_ACCESSOR,
  NgControl,
} from '@angular/forms';
import { ErrorStateMatcher } from '@angular/material/core';
import { MatAutocompleteModule } from '@angular/material/autocomplete';
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatIconModule } from '@angular/material/icon';
import { MatInputModule } from '@angular/material/input';
import {
  createUniqueId,
  hasAccessibleName,
  mergeAriaIds,
  warnInDev,
} from '../../a11y';

export interface MfAutocompleteOption {
  value: string | number;
  label: string;
  disabled?: boolean;
}

export type MfAutocompleteSize = 'sm' | 'md' | 'lg';

/**
 * Autocompletar de la librerÃ­a ng-comps.
 * Envuelve Angular Material `mat-autocomplete` y expone una API uniforme
 * con look and feel de marca.
 *
 * El panel desplegable se estiliza con la clase global `mf-autocomplete-panel`.
 * Puedes aÃ±adir clases adicionales con `panelClass`.
 */
@Component({
  selector: 'mf-autocomplete',
  imports: [
    MatAutocompleteModule,
    MatFormFieldModule,
    MatIconModule,
    MatInputModule,
  ],
  providers: [
    {
      provide: NG_VALUE_ACCESSOR,
      useExisting: forwardRef(() => MfAutocompleteComponent),
      multi: true,
    },
  ],
  template: `
    <mat-form-field [appearance]="'outline'" [class]="hostClasses()">
      @if (label()) {
        <mat-label>{{ label() }}</mat-label>
      }
      @if (leadingIcon()) {
        <mat-icon matPrefix aria-hidden="true">{{ leadingIcon() }}</mat-icon>
      }
      <input
        matInput
        [id]="controlId()"
        [placeholder]="placeholder()"
        [disabled]="isDisabled()"
        [required]="required()"
        [matAutocomplete]="auto"
        [value]="internalValue()"
        [errorStateMatcher]="errorStateMatcher"
        [attr.aria-label]="resolvedAriaLabel()"
        [attr.aria-labelledby]="ariaLabelledby() || null"
        [attr.aria-describedby]="describedBy()"
        [attr.aria-invalid]="isInvalid() ? 'true' : null"
        [attr.aria-required]="required() ? 'true' : null"
        (input)="onInputChange($event)"
        (blur)="onBlur()"
      />
      @if (trailingIcon()) {
        <mat-icon matSuffix aria-hidden="true">{{ trailingIcon() }}</mat-icon>
      }
      @if (hint()) {
        <mat-hint [attr.id]="hintId()">{{ hint() }}</mat-hint>
      }
      <mat-autocomplete
        #auto
        [panelWidth]="panelWidth()"
        [class]="autocompletePanelClasses()"
        (optionSelected)="onOptionSelected($event)"
      >
        @for (option of filteredOptions(); track option.value) {
          <mat-option [value]="option.label" [disabled]="option.disabled ?? false">
            {{ option.label }}
          </mat-option>
        }
      </mat-autocomplete>
    </mat-form-field>
    @if (error()) {
      <p class="mf-autocomplete__error" [attr.id]="errorId()" role="alert">
        {{ error() }}
      </p>
    }
  `,
  styleUrl: './mf-autocomplete.component.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class MfAutocompleteComponent implements ControlValueAccessor {
  private readonly cdr = inject(ChangeDetectorRef);
  private readonly ngControl = inject(NgControl, { self: true, optional: true });
  private readonly generatedId = createUniqueId('mf-autocomplete');
  private readonly disabledFromForm = signal(false);
  protected readonly internalValue = signal('');
  private onControlChange: (value: string) => void = () => undefined;
  private onControlTouched: () => void = () => undefined;
  readonly errorStateMatcher: ErrorStateMatcher = {
    isErrorState: (control) =>
      Boolean(
        this.error() || (control?.invalid && (control.touched || control.dirty)),
      ),
  };

  /** Lista completa de opciones */
  readonly options = input.required<MfAutocompleteOption[]>();
  /** ID del control */
  readonly id = input<string | undefined>(undefined);
  /** Etiqueta flotante del campo */
  readonly label = input<string | undefined>(undefined);
  /** Etiqueta accesible alternativa cuando no existe label visible */
  readonly ariaLabel = input<string | undefined>(undefined);
  /** Referencia externa a elementos que etiquetan el control */
  readonly ariaLabelledby = input<string | undefined>(undefined);
  /** Referencia externa a elementos descriptivos adicionales */
  readonly ariaDescribedby = input<string | undefined>(undefined);
  /** Placeholder del input */
  readonly placeholder = input('');
  /** Valor actual (texto en el campo) */
  readonly value = input('');
  /** Deshabilitado */
  readonly disabled = input(false);
  /** Requerido */
  readonly required = input(false);
  /** TamaÃ±o del campo */
  readonly size = input<MfAutocompleteSize>('md');
  /** Ancho completo */
  readonly fullWidth = input(false);
  /** Texto de ayuda debajo del campo */
  readonly hint = input<string | undefined>(undefined);
  /** Mensaje de error */
  readonly error = input<string | undefined>(undefined);
  /** Icono al inicio del campo */
  readonly leadingIcon = input<string | undefined>(undefined);
  /** Icono al final del campo */
  readonly trailingIcon = input<string | undefined>(undefined);
  /**
   * Ancho del panel del autocomplete.
   * Por defecto `''`: el panel toma el mismo ancho que el campo.
   * Acepta cualquier valor CSS vÃ¡lido ('300px', '80vw', etc.) para sobreescribirlo.
   */
  readonly panelWidth = input<string | number>('');
  /**
   * Clases extra que se aÃ±aden al panel del autocomplete (overlay).
   * La clase `mf-autocomplete-panel` siempre estÃ¡ presente.
   */
  readonly panelClass = input<string | string[]>('');

  /** Emite el texto escrito en el campo */
  readonly mfInput = output<string>();
  /** Emite el valor de la opciÃ³n seleccionada */
  readonly mfOptionSelected = output<MfAutocompleteOption>();
  readonly mfBlur = output<void>();

  constructor() {
    effect(() => {
      this.internalValue.set(this.value());
    });

    effect(() => {
      if (
        !hasAccessibleName(
          this.label(),
          this.ariaLabel(),
          this.ariaLabelledby(),
        )
      ) {
        warnInDev(
          'mf-autocomplete requiere `label`, `ariaLabel` o `ariaLabelledby` para exponer un nombre accesible.',
        );
      }
    });
  }

  readonly controlId = computed(() => this.id() ?? this.generatedId);
  readonly hintId = computed(() =>
    this.hint() ? `${this.controlId()}-hint` : null,
  );
  readonly errorId = computed(() =>
    this.error() ? `${this.controlId()}-error` : null,
  );
  readonly describedBy = computed(() =>
    mergeAriaIds(this.ariaDescribedby(), this.hintId(), this.errorId()),
  );
  readonly resolvedAriaLabel = computed(() =>
    this.label() ? null : this.ariaLabel() ?? null,
  );
  readonly isDisabled = computed(
    () => this.disabled() || this.disabledFromForm(),
  );

  readonly hostClasses = computed(() => {
    const classes = ['mf-autocomplete', `mf-autocomplete--${this.size()}`];
    if (this.fullWidth()) classes.push('mf-autocomplete--full');
    if (this.error()) classes.push('mf-autocomplete--error');
    return classes.join(' ');
  });

  readonly autocompletePanelClasses = computed(() => {
    const base = ['mf-autocomplete-panel'];
    const extra = this.panelClass();

    if (Array.isArray(extra)) {
      base.push(...extra.filter(Boolean));
    } else if (extra) {
      base.push(extra);
    }

    return base.join(' ');
  });

  readonly filteredOptions = computed(() => {
    const query = this.internalValue().toLowerCase().trim();
    if (!query) {
      return this.options();
    }

    return this.options().filter((option) =>
      option.label.toLowerCase().includes(query),
    );
  });

  get inputValue(): string {
    return this.internalValue();
  }

  set inputValue(value: string) {
    this.internalValue.set(value);
  }

  writeValue(value: string | null): void {
    this.internalValue.set(value ?? '');
    this.cdr.markForCheck();
  }

  registerOnChange(fn: (value: string) => void): void {
    this.onControlChange = fn;
  }

  registerOnTouched(fn: () => void): void {
    this.onControlTouched = fn;
  }

  setDisabledState(isDisabled: boolean): void {
    this.disabledFromForm.set(isDisabled);
    this.cdr.markForCheck();
  }

  isInvalid(): boolean {
    const control = this.ngControl?.control;
    return Boolean(
      this.error() || (control?.invalid && (control.touched || control.dirty)),
    );
  }

  onInputChange(event: Event | string): void {
    const value =
      typeof event === 'string'
        ? event
        : (event.target as HTMLInputElement).value;

    this.internalValue.set(value);
    this.onControlChange(value);
    this.mfInput.emit(value);
  }

  onOptionSelected(event: { option: { value: string } }): void {
    const label = event.option.value;
    const match = this.options().find((option) => option.label === label);

    if (match) {
      this.internalValue.set(match.label);
      this.onControlChange(match.label);
      this.onControlTouched();
      this.mfOptionSelected.emit(match);
    }
  }

  onBlur(): void {
    this.onControlTouched();
    this.mfBlur.emit();
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  output,
} from '@angular/core';
import { MatIconModule } from '@angular/material/icon';

export interface MfBreadcrumbItem {
  label: string;
  href?: string;
  icon?: string;
}

/**
 * Breadcrumb de la librería ng-comps.
 * Componente de navegación jerárquica para indicar la ubicación
 * del usuario en la aplicación.
 */
@Component({
  selector: 'mf-breadcrumb',
  imports: [MatIconModule],
  template: `
    <nav [attr.aria-label]="ariaLabel()" [class]="hostClasses()">
      <ol class="mf-breadcrumb__list">
        @for (item of items(); track item.label; let last = $last) {
          <li class="mf-breadcrumb__item">
            @if (!last && item.href) {
              <a
                class="mf-breadcrumb__link"
                [href]="item.href"
                (click)="onItemClick($event, item)"
              >
                @if (item.icon) {
                  <mat-icon class="mf-breadcrumb__icon" aria-hidden="true">{{ item.icon }}</mat-icon>
                }
                {{ item.label }}
              </a>
            } @else {
              <span class="mf-breadcrumb__current" [attr.aria-current]="last ? 'page' : null">
                @if (item.icon) {
                  <mat-icon class="mf-breadcrumb__icon" aria-hidden="true">{{ item.icon }}</mat-icon>
                }
                {{ item.label }}
              </span>
            }
            @if (!last) {
              <mat-icon class="mf-breadcrumb__separator" aria-hidden="true">{{ separator() }}</mat-icon>
            }
          </li>
        }
      </ol>
    </nav>
  `,
  styleUrl: './mf-breadcrumb.component.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class MfBreadcrumbComponent {
  /** Items del breadcrumb */
  readonly items = input.required<MfBreadcrumbItem[]>();
  /** Icono separador */
  readonly separator = input<string>('chevron_right');
  /** Label de accesibilidad */
  readonly ariaLabel = input<string>('Breadcrumb');

  readonly mfItemClick = output<MfBreadcrumbItem>();

  readonly hostClasses = computed(() => 'mf-breadcrumb');

  onItemClick(event: Event, item: MfBreadcrumbItem): void {
    event.preventDefault();
    this.mfItemClick.emit(item);
  }
}

import { Injectable, TemplateRef, Type, inject } from '@angular/core';
import {
  DialogRole,
  MatDialog,
  MatDialogConfig,
  MatDialogRef,
} from '@angular/material/dialog';

export interface MfDialogOpenConfig<D = unknown>
  extends Omit<
    MatDialogConfig<D>,
    | 'ariaDescribedBy'
    | 'ariaLabel'
    | 'ariaLabelledBy'
    | 'autoFocus'
    | 'panelClass'
    | 'restoreFocus'
    | 'role'
  > {
  ariaLabel?: string;
  ariaLabelledby?: string;
  ariaDescribedby?: string;
  autoFocus?: MatDialogConfig<D>['autoFocus'];
  panelClass?: string | string[];
  restoreFocus?: boolean;
  role?: DialogRole;
}

@Injectable({ providedIn: 'root' })
export class MfDialogService {
  private readonly dialog = inject(MatDialog);

  open<T, D = unknown, R = unknown>(
    component: Type<T> | TemplateRef<T>,
    config: MfDialogOpenConfig<D> = {},
  ): MatDialogRef<T, R> {
    const panelClass = Array.isArray(config.panelClass)
      ? ['mf-dialog-panel', ...config.panelClass]
      : ['mf-dialog-panel', ...(config.panelClass ? [config.panelClass] : [])];

    return this.dialog.open(component, {
      ...config,
      role: config.role ?? 'dialog',
      autoFocus: config.autoFocus ?? 'first-tabbable',
      restoreFocus: config.restoreFocus ?? true,
      ariaLabel: config.ariaLabel,
      ariaLabelledBy: config.ariaLabelledby,
      ariaDescribedBy: config.ariaDescribedby,
      panelClass,
    });
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  input,
} from '@angular/core';
import { MatGridListModule } from '@angular/material/grid-list';

export interface MfGridTile {
  /** Título de la tile */
  title?: string;
  /** Subtítulo de la tile */
  subtitle?: string;
  /** Número de columnas que ocupa */
  colspan?: number;
  /** Número de filas que ocupa */
  rowspan?: number;
  /** Color de fondo */
  background?: string;
}

/**
 * Lista en cuadrícula de la librería ng-comps.
 * Envuelve Angular Material `mat-grid-list` y expone una API uniforme
 * con look and feel de marca. Soporta tiles estáticas y content projection.
 */
@Component({
  selector: 'mf-grid-list',
  imports: [MatGridListModule],
  template: `
    <mat-grid-list
      class="mf-grid-list"
      [cols]="cols()"
      [rowHeight]="rowHeight()"
      [gutterSize]="gutterSize()"
    >
      @for (tile of tiles(); track $index) {
        <mat-grid-tile
          class="mf-grid-list__tile"
          [colspan]="tile.colspan ?? 1"
          [rowspan]="tile.rowspan ?? 1"
          [style.background]="tile.background || null"
        >
          <mat-grid-tile-header>
            @if (tile.title) {
              <span class="mf-grid-list__tile-title">{{ tile.title }}</span>
            }
            @if (tile.subtitle) {
              <span class="mf-grid-list__tile-subtitle">{{ tile.subtitle }}</span>
            }
          </mat-grid-tile-header>
        </mat-grid-tile>
      }
      <ng-content />
    </mat-grid-list>
  `,
  styleUrl: './mf-grid-list.component.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class MfGridListComponent {
  /** Número de columnas */
  readonly cols = input(2);
  /** Altura de cada fila */
  readonly rowHeight = input<string | number>('1:1');
  /** Espacio entre tiles */
  readonly gutterSize = input('8px');
  /** Tiles a renderizar */
  readonly tiles = input<MfGridTile[]>([]);
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  output,
} from '@angular/core';
import { MatMenuModule } from '@angular/material/menu';
import { MatButtonModule } from '@angular/material/button';
import { MatIconModule } from '@angular/material/icon';

export interface MfMenuItem {
  label: string;
  icon?: string;
  disabled?: boolean;
  value: string;
}

/**
 * Menu de la librería ng-comps.
 * Envuelve Angular Material `mat-menu` y expone una API uniforme
 * con look and feel de marca.
 */
@Component({
  selector: 'mf-menu',
  imports: [MatMenuModule, MatButtonModule, MatIconModule],
  template: `
    <button
      mat-icon-button
      [matMenuTriggerFor]="menu"
      [class]="triggerClasses()"
      [attr.aria-label]="triggerLabel()"
    >
      <mat-icon>{{ triggerIcon() }}</mat-icon>
    </button>
    <mat-menu #menu="matMenu" [class]="hostClasses()">
      @for (item of items(); track item.value) {
        <button
          mat-menu-item
          [disabled]="item.disabled ?? false"
          (click)="mfItemClick.emit(item.value)"
        >
          @if (item.icon) {
            <mat-icon aria-hidden="true">{{ item.icon }}</mat-icon>
          }
          <span>{{ item.label }}</span>
        </button>
      }
    </mat-menu>
  `,
  styleUrl: './mf-menu.component.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class MfMenuComponent {
  /** Items del menú */
  readonly items = input.required<MfMenuItem[]>();
  /** Icono del trigger */
  readonly triggerIcon = input<string>('more_vert');
  /** Label accesible del trigger */
  readonly triggerLabel = input<string>('Open menu');

  readonly mfItemClick = output<string>();

  readonly hostClasses = computed(() => 'mf-menu');
  readonly triggerClasses = computed(() => 'mf-menu__trigger');
}

import {
  ChangeDetectionStrategy,
  ChangeDetectorRef,
  Component,
  computed,
  effect,
  forwardRef,
  inject,
  input,
  output,
  signal,
} from '@angular/core';
import {
  ControlValueAccessor,
  NG_VALUE_ACCESSOR,
  NgControl,
} from '@angular/forms';
import { MatRadioModule } from '@angular/material/radio';
import {
  createUniqueId,
  hasAccessibleName,
  mergeAriaIds,
  warnInDev,
} from '../../a11y';

export interface MfRadioOption {
  /** Valor de la opciÃ³n */
  value: string;
  /** Texto visible */
  label: string;
  /** Deshabilitada individualmente */
  disabled?: boolean;
}

export type MfRadioDirection = 'horizontal' | 'vertical';

/**
 * Grupo de radio buttons de la librerÃ­a ng-comps.
 * Envuelve Angular Material `mat-radio-group` + `mat-radio-button`
 * y expone una API uniforme con look and feel de marca.
 */
@Component({
  selector: 'mf-radio-button',
  imports: [MatRadioModule],
  providers: [
    {
      provide: NG_VALUE_ACCESSOR,
      useExisting: forwardRef(() => MfRadioButtonComponent),
      multi: true,
    },
  ],
  template: `
    <fieldset class="mf-radio__fieldset">
      @if (label()) {
        <legend class="mf-radio__legend" [id]="legendId()">
          {{ label() }}
          @if (required()) {
            <span aria-hidden="true"> *</span>
          }
        </legend>
      }

      <mat-radio-group
        [class]="hostClasses()"
        [disabled]="isDisabled()"
        [name]="groupName()"
        [required]="required()"
        [value]="internalValue()"
        [attr.aria-label]="resolvedAriaLabel()"
        [attr.aria-labelledby]="computedLabelledby()"
        [attr.aria-describedby]="describedBy()"
        [attr.aria-invalid]="isInvalid() ? 'true' : null"
        [attr.aria-required]="required() ? 'true' : null"
        (change)="onChange($event)"
      >
        @for (option of options(); track option.value) {
          <mat-radio-button
            class="mf-radio__option"
            [value]="option.value"
            [disabled]="option.disabled ?? false"
          >
            {{ option.label }}
          </mat-radio-button>
        }
      </mat-radio-group>

      @if (hint()) {
        <p class="mf-radio__hint" [attr.id]="hintId()">{{ hint() }}</p>
      }

      @if (error()) {
        <p class="mf-radio__error" [attr.id]="errorId()" role="alert">
          {{ error() }}
        </p>
      }
    </fieldset>
  `,
  styleUrl: './mf-radio-button.component.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class MfRadioButtonComponent implements ControlValueAccessor {
  private readonly cdr = inject(ChangeDetectorRef);
  private readonly ngControl = inject(NgControl, { self: true, optional: true });
  private readonly generatedId = createUniqueId('mf-radio');
  private readonly disabledFromForm = signal(false);
  protected readonly internalValue = signal<string | undefined>(undefined);
  private onControlChange: (value: string) => void = () => undefined;
  private onControlTouched: () => void = () => undefined;

  /** Opciones del grupo */
  readonly options = input.required<MfRadioOption[]>();
  /** ID del control */
  readonly id = input<string | undefined>(undefined);
  /** Etiqueta visible del grupo */
  readonly label = input<string | undefined>(undefined);
  /** Valor seleccionado */
  readonly value = input<string | undefined>(undefined);
  /** Deshabilitado */
  readonly disabled = input(false);
  /** Requerido */
  readonly required = input(false);
  /** DirecciÃ³n del grupo */
  readonly direction = input<MfRadioDirection>('vertical');
  /** Nombre accesible alternativo del grupo */
  readonly ariaLabel = input<string | undefined>(undefined);
  /** Etiqueta accesible para el grupo */
  readonly ariaLabelledby = input<string | undefined>(undefined);
  /** Referencia externa a elementos descriptivos adicionales */
  readonly ariaDescribedby = input<string | undefined>(undefined);
  /** Texto de ayuda */
  readonly hint = input<string | undefined>(undefined);
  /** Mensaje de error */
  readonly error = input<string | undefined>(undefined);
  /** Name del grupo */
  readonly name = input<string | undefined>(undefined);

  readonly mfChange = output<string>();

  constructor() {
    effect(() => {
      this.internalValue.set(this.value());
    });

    effect(() => {
      if (
        !hasAccessibleName(
          this.label(),
          this.ariaLabel(),
          this.ariaLabelledby(),
        )
      ) {
        warnInDev(
          'mf-radio-button requiere `label`, `ariaLabel` o `ariaLabelledby` para exponer un nombre accesible.',
        );
      }
    });
  }

  readonly controlId = computed(() => this.id() ?? this.generatedId);
  readonly legendId = computed(() => `${this.controlId()}-legend`);
  readonly hintId = computed(() =>
    this.hint() ? `${this.controlId()}-hint` : null,
  );
  readonly errorId = computed(() =>
    this.error() ? `${this.controlId()}-error` : null,
  );
  readonly computedLabelledby = computed(() =>
    mergeAriaIds(
      this.ariaLabelledby(),
      this.label() ? this.legendId() : null,
    ),
  );
  readonly describedBy = computed(() =>
    mergeAriaIds(this.ariaDescribedby(), this.hintId(), this.errorId()),
  );
  readonly groupName = computed(() => this.name() ?? this.controlId());
  readonly resolvedAriaLabel = computed(() =>
    this.label() ? null : this.ariaLabel() ?? null,
  );
  readonly isDisabled = computed(
    () => this.disabled() || this.disabledFromForm(),
  );

  readonly hostClasses = computed(() => {
    return `mf-radio mf-radio--${this.direction()}`;
  });

  writeValue(value: string | null): void {
    this.internalValue.set(value ?? undefined);
    this.cdr.markForCheck();
  }

  registerOnChange(fn: (value: string) => void): void {
    this.onControlChange = fn;
  }

  registerOnTouched(fn: () => void): void {
    this.onControlTouched = fn;
  }

  setDisabledState(isDisabled: boolean): void {
    this.disabledFromForm.set(isDisabled);
    this.cdr.markForCheck();
  }

  isInvalid(): boolean {
    const control = this.ngControl?.control;
    return Boolean(
      this.error() || (control?.invalid && (control.touched || control.dirty)),
    );
  }

  onChange(event: { value: string }): void {
    this.internalValue.set(event.value);
    this.onControlChange(event.value);
    this.onControlTouched();
    this.mfChange.emit(event.value);
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  effect,
  input,
  output,
  signal,
} from '@angular/core';
import { MatButtonModule } from '@angular/material/button';
import { PageEvent } from '@angular/material/paginator';
import { MatIconModule } from '@angular/material/icon';
import { MatMenuModule } from '@angular/material/menu';
import { MatSortModule, Sort } from '@angular/material/sort';
import { MatTableModule } from '@angular/material/table';
import { MfInputComponent } from '../input';
import { MfPaginatorComponent } from '../paginator';

export type MfTableCellType = 'text' | 'number' | 'date' | 'badge';
export type MfTableAlign = 'start' | 'center' | 'end';
export type MfTableVariant = 'default' | 'striped' | 'bordered';
export type MfTableDensity = 'compact' | 'comfortable' | 'spacious';
export type MfTableBadgeTone =
  | 'brand'
  | 'success'
  | 'warning'
  | 'error'
  | 'neutral';
export type MfTableActionTone = 'primary' | 'neutral' | 'danger';

export interface MfTableColumn {
  key: string;
  header: string;
  sortable?: boolean;
  type?: MfTableCellType;
  align?: MfTableAlign;
  width?: string;
  hidden?: boolean;
  truncate?: boolean;
  searchable?: boolean;
  emptyValue?: string;
  formatter?: (value: unknown, row: Record<string, unknown>) => string;
  sortAccessor?: (row: Record<string, unknown>) => unknown;
  searchAccessor?: (row: Record<string, unknown>) => string;
  badgeTone?:
    | MfTableBadgeTone
    | ((value: unknown, row: Record<string, unknown>) => MfTableBadgeTone);
  badgeTones?: Record<string, MfTableBadgeTone>;
}

export interface MfTableRowAction {
  key: string;
  label: string;
  icon?: string;
  tone?: MfTableActionTone;
  disabled?: boolean | ((row: Record<string, unknown>) => boolean);
  ariaLabel?: (row: Record<string, unknown>) => string;
}

interface MfResolvedTableAction extends MfTableRowAction {
  legacy?: boolean;
}

/**
 * Enterprise-oriented table component with optional search, pagination,
 * badges, explicit row actions and client-side sorting.
 */
@Component({
  selector: 'mf-table',
  imports: [
    MatTableModule,
    MatSortModule,
    MatButtonModule,
    MatIconModule,
    MatMenuModule,
    MfInputComponent,
    MfPaginatorComponent,
  ],
  template: `
    <section [class]="hostClasses()">
      @if (showsToolbar()) {
        <header class="mf-table__toolbar">
          <div class="mf-table__intro">
            @if (title()) {
              <h2 class="mf-table__title">{{ title() }}</h2>
            }
            @if (description()) {
              <p class="mf-table__description">{{ description() }}</p>
            }
            <div class="mf-table__meta">
              <span class="mf-table__metric">{{ resultSummary() }}</span>
              @if (searchTerm()) {
                <span class="mf-table__metric mf-table__metric--accent">
                  Filter active
                </span>
              }
              @if (sortState().direction) {
                <span class="mf-table__metric">
                  Sorted by {{ sortState().active }}
                </span>
              }
            </div>
          </div>

          @if (showSearch()) {
            <div class="mf-table__search">
              <mf-input
                [label]="searchLabel()"
                [ariaLabel]="searchLabel()"
                [placeholder]="searchPlaceholder()"
                [value]="localSearchTerm()"
                [type]="'search'"
                [leadingIcon]="'search'"
                [fullWidth]="true"
                (mfInput)="onSearchChange($event)"
              />
            </div>
          }
        </header>
      }

      @if (filteredRows().length > 0) {
        <div class="mf-table__surface">
          <div class="mf-table__wrapper">
            <table
              mat-table
              [dataSource]="paginatedRows()"
              matSort
              [matSortActive]="sortState().active"
              [matSortDirection]="sortState().direction"
              class="mf-table__table"
              (matSortChange)="onSortChange($event)"
            >
              @for (column of visibleColumns(); track column.key) {
                <ng-container [matColumnDef]="column.key">
                  @if (column.sortable) {
                    <th
                      mat-header-cell
                      *matHeaderCellDef
                      mat-sort-header
                      [style.width]="column.width || null"
                      [class]="headerCellClasses(column)"
                    >
                      {{ column.header }}
                    </th>
                  } @else {
                    <th
                      mat-header-cell
                      *matHeaderCellDef
                      [style.width]="column.width || null"
                      [class]="headerCellClasses(column)"
                    >
                      {{ column.header }}
                    </th>
                  }

                  <td
                    mat-cell
                    *matCellDef="let row"
                    [style.width]="column.width || null"
                    [class]="cellClasses(column)"
                  >
                    @if (column.type === 'badge') {
                      <span [class]="badgeClasses(column, row)">
                        {{ renderCell(column, row) }}
                      </span>
                    } @else {
                      <span class="mf-table__cell-text">
                        {{ renderCell(column, row) }}
                      </span>
                    }
                  </td>
                </ng-container>
              }

              @if (hasActions()) {
                <ng-container [matColumnDef]="actionColumnKey">
                  <th
                    mat-header-cell
                    *matHeaderCellDef
                    class="mf-table__actions-header"
                  >
                    {{ resolvedActionHeader() }}
                  </th>
                  <td
                    mat-cell
                    *matCellDef="let row"
                    class="mf-table__actions-cell"
                  >
                    @if (usesActionMenu()) {
                      <button
                        mat-icon-button
                        type="button"
                        class="mf-table__action-menu-trigger"
                        [matMenuTriggerFor]="actionMenu"
                        [attr.aria-label]="getRowMenuAriaLabel(row)"
                      >
                        <mat-icon aria-hidden="true">more_horiz</mat-icon>
                      </button>
                      <mat-menu
                        #actionMenu="matMenu"
                        xPosition="before"
                        class="mf-table__action-menu"
                      >
                        @for (action of resolvedActions(); track action.key) {
                          <button
                            mat-menu-item
                            [disabled]="isActionDisabled(action, row)"
                            [attr.aria-label]="getActionAriaLabel(action, row)"
                            (click)="onActionClick(action, row)"
                          >
                            @if (action.icon) {
                              <mat-icon aria-hidden="true">{{ action.icon }}</mat-icon>
                            }
                            <span>{{ action.label }}</span>
                          </button>
                        }
                      </mat-menu>
                    } @else {
                      <div class="mf-table__action-group">
                        @for (action of resolvedActions(); track action.key) {
                          <button
                            mat-stroked-button
                            type="button"
                            [class]="actionClasses(action)"
                            [disabled]="isActionDisabled(action, row)"
                            [attr.aria-label]="getActionAriaLabel(action, row)"
                            (click)="onActionClick(action, row)"
                          >
                            @if (action.icon) {
                              <mat-icon aria-hidden="true">{{ action.icon }}</mat-icon>
                            }
                            <span>{{ action.label }}</span>
                          </button>
                        }
                      </div>
                    }
                  </td>
                </ng-container>
              }

              <tr
                mat-header-row
                *matHeaderRowDef="displayedColumns(); sticky: stickyHeader()"
              ></tr>
              <tr
                mat-row
                *matRowDef="let row; columns: displayedColumns()"
                class="mf-table__row"
              ></tr>
            </table>
          </div>

          @if (showPaginator()) {
            <footer class="mf-table__footer">
              <mf-paginator
                [length]="filteredRows().length"
                [pageSize]="localPageSize()"
                [pageIndex]="localPageIndex()"
                [pageSizeOptions]="pageSizeOptions()"
                [showFirstLastButtons]="showFirstLastButtons()"
                [hidePageSize]="hidePageSize()"
                (mfPageChange)="onPageChange($event)"
              />
            </footer>
          }
        </div>
      } @else {
        <div class="mf-table__empty">
          <div class="mf-table__empty-icon">
            <mat-icon aria-hidden="true">table_rows</mat-icon>
          </div>
          <h3 class="mf-table__empty-title">{{ emptyTitle() }}</h3>
          <p class="mf-table__empty-description">{{ emptyDescriptionText() }}</p>
        </div>
      }
    </section>
  `,
  styleUrl: './mf-table.component.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class MfTableComponent {
  protected readonly localSearchTerm = signal('');
  protected readonly localPageIndex = signal(0);
  protected readonly localPageSize = signal(10);
  protected readonly sortState = signal<Sort>({ active: '', direction: '' });
  protected readonly actionColumnKey = 'mf-row-action';

  readonly columns = input<MfTableColumn[]>([]);
  readonly data = input<Record<string, unknown>[]>([]);
  readonly variant = input<MfTableVariant>('default');
  readonly density = input<MfTableDensity>('comfortable');
  readonly title = input<string | undefined>(undefined);
  readonly description = input<string | undefined>(undefined);
  readonly showSearch = input(false);
  readonly searchLabel = input('Search');
  readonly searchPlaceholder = input('Search records');
  readonly searchValue = input('');
  readonly showPaginator = input(false);
  readonly pageSize = input(10);
  readonly pageIndex = input(0);
  readonly pageSizeOptions = input<number[]>([10, 25, 50, 100]);
  readonly showFirstLastButtons = input(true);
  readonly hidePageSize = input(false);
  readonly stickyHeader = input(false);
  readonly emptyTitle = input('No records found');
  readonly emptyDescription = input(
    'This dataset has no rows yet. Connect data or add records to populate the table.',
  );

  readonly rowActionLabel = input<string | undefined>(undefined);
  readonly rowActionHeader = input('Actions');
  readonly rowActionAriaLabel = input<
    ((row: Record<string, unknown>) => string) | undefined
  >(undefined);
  readonly rowActions = input<MfTableRowAction[]>([]);

  readonly mfSortChange = output<Sort>();
  readonly mfSearchChange = output<string>();
  readonly mfPageChange = output<PageEvent>();
  readonly mfAction = output<{
    action: MfTableRowAction;
    row: Record<string, unknown>;
  }>();
  readonly mfRowAction = output<Record<string, unknown>>();
  readonly mfRowClick = output<Record<string, unknown>>();

  constructor() {
    effect(() => {
      this.localSearchTerm.set(this.searchValue());
    });

    effect(() => {
      this.localPageIndex.set(this.pageIndex());
    });

    effect(() => {
      this.localPageSize.set(this.pageSize());
    });

    effect(() => {
      const totalRows = this.filteredRows().length;
      const pageSize = Math.max(this.localPageSize(), 1);
      const maxPageIndex = Math.max(Math.ceil(totalRows / pageSize) - 1, 0);

      if (this.localPageIndex() > maxPageIndex) {
        this.localPageIndex.set(maxPageIndex);
      }
    });
  }

  protected readonly visibleColumns = computed(() =>
    this.columns().filter((column) => !column.hidden),
  );

  protected readonly searchTerm = computed(() => this.localSearchTerm().trim());
  protected readonly showsToolbar = computed(
    () => Boolean(this.title() || this.description() || this.showSearch()),
  );
  protected readonly resolvedActionHeader = computed(() => this.rowActionHeader());

  protected readonly resolvedActions = computed<MfResolvedTableAction[]>(() => {
    const actions: MfResolvedTableAction[] = [...this.rowActions()];

    if (this.rowActionLabel()) {
      actions.unshift({
        key: 'legacy-action',
        label: this.rowActionLabel() as string,
        tone: 'neutral',
        ariaLabel: this.rowActionAriaLabel(),
        legacy: true,
      });
    }

    return actions;
  });

  protected readonly hasActions = computed(() => this.resolvedActions().length > 0);
  protected readonly usesActionMenu = computed(
    () => this.resolvedActions().length > 1,
  );

  readonly displayedColumns = computed(() => {
    const columns = this.visibleColumns().map((column) => column.key);

    if (this.hasActions()) {
      columns.push(this.actionColumnKey);
    }

    return columns;
  });

  protected readonly filteredRows = computed(() => {
    const query = this.searchTerm().toLowerCase();
    const rows = this.data();

    if (!query) {
      return rows;
    }

    const searchableColumns = this.visibleColumns().filter(
      (column) => column.searchable !== false,
    );

    return rows.filter((row) =>
      searchableColumns.some((column) =>
        this.getSearchValue(column, row).toLowerCase().includes(query),
      ),
    );
  });

  protected readonly sortedRows = computed(() => {
    const rows = [...this.filteredRows()];
    const { active, direction } = this.sortState();

    if (!active || !direction) {
      return rows;
    }

    const column = this.visibleColumns().find((item) => item.key === active);
    if (!column) {
      return rows;
    }

    return rows.sort((left, right) => {
      const leftValue = this.normalizeSortValue(column, left);
      const rightValue = this.normalizeSortValue(column, right);

      if (leftValue < rightValue) {
        return direction === 'asc' ? -1 : 1;
      }

      if (leftValue > rightValue) {
        return direction === 'asc' ? 1 : -1;
      }

      return 0;
    });
  });

  protected readonly paginatedRows = computed(() => {
    if (!this.showPaginator()) {
      return this.sortedRows();
    }

    const size = Math.max(this.localPageSize(), 1);
    const start = this.localPageIndex() * size;
    return this.sortedRows().slice(start, start + size);
  });

  protected readonly resultSummary = computed(() => {
    const filtered = this.filteredRows().length;
    const total = this.data().length;

    if (filtered === total) {
      return `${total} records`;
    }

    return `${filtered} of ${total} records`;
  });

  onSearchChange(value: string): void {
    this.localSearchTerm.set(value);
    this.localPageIndex.set(0);
    this.mfSearchChange.emit(value);
  }

  onSortChange(sort: Sort): void {
    this.sortState.set(sort);
    this.localPageIndex.set(0);
    this.mfSortChange.emit(sort);
  }

  onPageChange(event: PageEvent): void {
    this.localPageIndex.set(event.pageIndex);
    this.localPageSize.set(event.pageSize);
    this.mfPageChange.emit(event);
  }

  onActionClick(action: MfResolvedTableAction, row: Record<string, unknown>): void {
    if (action.legacy) {
      this.mfRowAction.emit(row);
      this.mfRowClick.emit(row);
    }

    this.mfAction.emit({ action, row });
  }

  renderCell(column: MfTableColumn, row: Record<string, unknown>): string {
    const value = this.getRawValue(column, row);

    if (column.formatter) {
      return column.formatter(value, row);
    }

    if (value === null || value === undefined || value === '') {
      return column.emptyValue ?? '-';
    }

    if (column.type === 'number' && typeof value === 'number') {
      return new Intl.NumberFormat('es-ES').format(value);
    }

    if (column.type === 'date') {
      const date = value instanceof Date ? value : new Date(String(value));
      if (!Number.isNaN(date.getTime())) {
        return new Intl.DateTimeFormat('es-ES').format(date);
      }
    }

    return String(value);
  }

  headerCellClasses(column: MfTableColumn): string {
    return [
      'mf-table__header-cell',
      `mf-table__cell--align-${column.align ?? 'start'}`,
    ].join(' ');
  }

  cellClasses(column: MfTableColumn): string {
    const classes = [
      'mf-table__cell',
      `mf-table__cell--align-${column.align ?? 'start'}`,
    ];

    if (column.truncate) {
      classes.push('mf-table__cell--truncate');
    }

    return classes.join(' ');
  }

  badgeClasses(column: MfTableColumn, row: Record<string, unknown>): string {
    return [
      'mf-table__badge',
      `mf-table__badge--${this.resolveBadgeTone(column, row)}`,
    ].join(' ');
  }

  actionClasses(action: MfResolvedTableAction): string {
    return [
      'mf-table__action',
      `mf-table__action--${action.tone ?? 'neutral'}`,
    ].join(' ');
  }

  isActionDisabled(
    action: MfResolvedTableAction,
    row: Record<string, unknown>,
  ): boolean {
    return typeof action.disabled === 'function'
      ? action.disabled(row)
      : Boolean(action.disabled);
  }

  getActionAriaLabel(
    action: MfResolvedTableAction,
    row: Record<string, unknown>,
  ): string | null {
    return action.ariaLabel?.(row) ?? action.label ?? null;
  }

  getRowMenuAriaLabel(row: Record<string, unknown>): string {
    const primaryColumn = this.visibleColumns()[0];
    const primaryLabel = primaryColumn
      ? this.renderCell(primaryColumn, row)
      : 'this row';

    return `Open actions for ${primaryLabel}`;
  }

  emptyDescriptionText(): string {
    if (this.searchTerm()) {
      return 'No rows match the current search. Try a broader query or clear the filter.';
    }

    return this.emptyDescription();
  }

  readonly hostClasses = computed(() =>
    ['mf-table', `mf-table--${this.variant()}`, `mf-table--${this.density()}`].join(
      ' ',
    ),
  );

  private getCellValue(
    column: MfTableColumn,
    row: Record<string, unknown>,
  ): unknown {
    return column.sortAccessor ? column.sortAccessor(row) : this.getRawValue(column, row);
  }

  private getRawValue(
    column: MfTableColumn,
    row: Record<string, unknown>,
  ): unknown {
    return row[column.key];
  }

  private getSearchValue(
    column: MfTableColumn,
    row: Record<string, unknown>,
  ): string {
    if (column.searchAccessor) {
      return column.searchAccessor(row);
    }

    return this.renderCell(column, row);
  }

  private normalizeSortValue(
    column: MfTableColumn,
    row: Record<string, unknown>,
  ): number | string {
    const value = this.getCellValue(column, row);

    if (value === null || value === undefined || value === '') {
      return '';
    }

    if (column.type === 'number') {
      return typeof value === 'number' ? value : Number(value);
    }

    if (column.type === 'date') {
      const date = value instanceof Date ? value : new Date(String(value));
      return Number.isNaN(date.getTime()) ? '' : date.getTime();
    }

    if (typeof value === 'number') {
      return value;
    }

    return String(value).toLocaleLowerCase();
  }

  private resolveBadgeTone(
    column: MfTableColumn,
    row: Record<string, unknown>,
  ): MfTableBadgeTone {
    const value = row[column.key];

    if (typeof column.badgeTone === 'function') {
      return column.badgeTone(value, row);
    }

    if (column.badgeTone) {
      return column.badgeTone;
    }

    return column.badgeTones?.[String(value)] ?? 'neutral';
  }
}

import {
  ChangeDetectionStrategy,
  ChangeDetectorRef,
  Component,
  computed,
  effect,
  forwardRef,
